<?php

namespace Tests\Integration;

use App\Models\User;
use App\Models\Template;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Illuminate\Support\Facades\Config;
use Illuminate\Support\Facades\Storage;
use Tests\TestCase;
use Spatie\Permission\Models\Role;

class TemplateControllerIntegrationTest extends TestCase
{
    use RefreshDatabase;

    protected string $documentDOCX;

    protected function setUp(): void
    {
        parent::setUp();

        Config::set('filesystems.default', 's3');

        if (!Role::where('name', \App\Enums\RoleType::ADMIN->value)->exists()) {
            Role::create(['name' => \App\Enums\RoleType::ADMIN->value]);
        }

        $this->documentDOCX = "data:@file/vnd.openxmlformats-officedocument.wordprocessingml.document;base64,";
    }

    public function test_store_end_to_end_with_real_s3()
    {
        $user = User::factory()->create();
        $user->assignRole(\App\Enums\RoleType::ADMIN->value);

        $response = $this->actingAs($user)->post(route('templates.store'), [
            'title'       => 'Integration Test Template',
            'category'    => 'Official',
            'description' => 'Testing real S3 upload',
            'document'    => $this->documentDOCX,
        ]);

        $response->assertRedirect();
        if (!session()->has('success')) {
            dump(session()->all());
        }
        $response->assertSessionHas('success');

        $template = Template::where('name', 'Integration Test Template')->first();
        $this->assertNotNull($template);
        
        $this->assertTrue(Storage::disk('s3')->exists($template->url));

        Storage::disk('s3')->delete($template->url);
    }
}
